import{_ as t,o as n,c as o,a0 as a}from"./chunks/framework.B3sz4m_N.js";const h=JSON.parse('{"title":"Hero Image Concepts — AI-Augmented Development Pipelines (Reconciled)","description":"","frontmatter":{},"headers":[],"relativePath":"reports/ai-augmented-dev-pipeline/hero-image-concepts.md","filePath":"reports/ai-augmented-dev-pipeline/hero-image-concepts.md"}'),r={name:"reports/ai-augmented-dev-pipeline/hero-image-concepts.md"};function s(i,e,l,g,p,d){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="hero-image-concepts-—-ai-augmented-development-pipelines-reconciled" tabindex="-1">Hero Image Concepts — AI-Augmented Development Pipelines (Reconciled) <a class="header-anchor" href="#hero-image-concepts-—-ai-augmented-development-pipelines-reconciled" aria-label="Permalink to &quot;Hero Image Concepts — AI-Augmented Development Pipelines (Reconciled)&quot;">​</a></h1><p>Pencil-drawn section header concepts. Style: hand-sketched linework, light pencil colouring, white or textured paper, minimal shading. No digital/glossy or cartoon aesthetics. Consistent visual language across all ten.</p><hr><h2 id="_1-overview" tabindex="-1">1. Overview <a class="header-anchor" href="#_1-overview" aria-label="Permalink to &quot;1. Overview&quot;">​</a></h2><p><strong>Section title:</strong> AI-Augmented Development Pipelines — Overview</p><p><strong>Core concept:</strong> A single pipeline where automated checks and a first-pass assistant run in parallel, but the final gate is always human: developer and reviewer in control, no autonomous merge.</p><p><strong>Visual metaphor:</strong> A river that splits into two channels (CI and PR-assist) then rejoins at a single gate—a small bridge or sluice—with a figure (human) at the gate holding a key or lever.</p><p><strong>Composition description:</strong> Horizontal flow left to right. The “river” is a soft pencil line; the fork is gentle, not mechanical. The gate is a simple arch or barrier. One small figure stands at the gate. Quiet, diagrammatic, not busy.</p><p><strong>Foreground elements:</strong> The gate/bridge, the single human figure, the converging pencil lines of the two channels.</p><p><strong>Background elements:</strong> Faint suggestion of landscape (low hills or horizon line), enough to ground the metaphor without detail.</p><p><strong>Labels:</strong> None, or one very subtle pencil label “human gate” only if needed for clarity.</p><p><strong>Suggested image prompt:</strong> Pencil sketch, hand-drawn style, white paper. A stream splits into two parallel channels then meets again at a small stone bridge; a single figure stands on the bridge. Soft pencil shading, no colour except light grey. Engineering report style, minimal, calm.</p><hr><h2 id="_2-pr-review-ai-augmented" tabindex="-1">2. PR Review (AI-Augmented) <a class="header-anchor" href="#_2-pr-review-ai-augmented" aria-label="Permalink to &quot;2. PR Review (AI-Augmented)&quot;">​</a></h2><p><strong>Section title:</strong> PR Review (AI-Augmented)</p><p><strong>Core concept:</strong> The bot sees only the diff and adds margin notes; the human reviewer holds the pen that approves or rejects. Comments, not control.</p><p><strong>Visual metaphor:</strong> A manuscript or scroll with a margin. One set of notes in a different “hand” (the bot’s first pass) in the margin; a second hand holds a pencil and is about to add or correct a note—the human reviewer.</p><p><strong>Composition description:</strong> Slightly angled view of a single page or scroll. Left: block of “text” suggested by ruled lines. Right margin: shorter pencil lines (marginalia). A hand with a pencil enters from the side, suggesting the human adding or approving.</p><p><strong>Foreground elements:</strong> The page/scroll, marginal pencil lines, one human hand with pencil.</p><p><strong>Background elements:</strong> Desk or surface implied by a single edge line; otherwise empty.</p><p><strong>Labels:</strong> None.</p><p><strong>Suggested image prompt:</strong> Pencil drawing on textured paper. Old manuscript or scroll with ruled lines and marginal notes in two different pencil “hands”; a human hand holding a pencil adds a note in the margin. Hand-sketched, light shading, no typography, professional report style.</p><hr><h2 id="_3-refactoring-ai-assisted" tabindex="-1">3. Refactoring (AI-Assisted) <a class="header-anchor" href="#_3-refactoring-ai-assisted" aria-label="Permalink to &quot;3. Refactoring (AI-Assisted)&quot;">​</a></h2><p><strong>Section title:</strong> Refactoring (AI-Assisted)</p><p><strong>Core concept:</strong> Incremental, rule-based improvement: suggestions applied by hand, then verified by a fixed set of checks (CI). No big-bang; small, ordered steps.</p><p><strong>Visual metaphor:</strong> A stone path or staircase being repaired: one stone at a time, with a checklist or ruler laid alongside to verify alignment.</p><p><strong>Composition description:</strong> A short flight of steps or a path of irregular stones. One stone is lifted or newly placed; a simple ruler or straightedge lies beside it. No machinery—only hand and tool.</p><p><strong>Foreground elements:</strong> The steps or path stones, one stone in focus, a ruler or gauge.</p><p><strong>Background elements:</strong> Faint suggestion of more path or landscape receding; soft pencil only.</p><p><strong>Labels:</strong> None.</p><p><strong>Suggested image prompt:</strong> Pencil sketch, hand-drawn. A stone path or staircase with one stone being adjusted; a ruler or straightedge beside it. Incremental repair, one step at a time. Light pencil, white paper, minimal shading, technical report aesthetic.</p><hr><h2 id="_4-migration-intelligence-php-wp-plugins" tabindex="-1">4. Migration Intelligence (PHP / WP / Plugins) <a class="header-anchor" href="#_4-migration-intelligence-php-wp-plugins" aria-label="Permalink to &quot;4. Migration Intelligence (PHP / WP / Plugins)&quot;">​</a></h2><p><strong>Section title:</strong> Migration Intelligence (PHP / WP / Plugins)</p><p><strong>Core concept:</strong> Understanding what breaks and in what order before moving: analysis and a runbook drafted from code context, then execution in small, ordered steps.</p><p><strong>Visual metaphor:</strong> A map with a route marked in segments—numbered or ordered—and a separate “legend” or runbook as a small folded sheet or index card beside the map.</p><p><strong>Composition description:</strong> A single sheet suggesting a map: a path or route broken into segments (simple numbered dots or dashes). Beside it, a smaller folded paper or card implying the runbook. No literal code or UI.</p><p><strong>Foreground elements:</strong> The map-like route, the segment markers, the runbook card.</p><p><strong>Background elements:</strong> Soft outline of “territory” or border; minimal.</p><p><strong>Labels:</strong> Optional tiny numerals (1, 2, 3) on the route; no other text.</p><p><strong>Suggested image prompt:</strong> Pencil drawing. A hand-drawn map with a route divided into clear segments and a small folded runbook or checklist beside it. Ordered journey, planning before execution. Pencil on white paper, light shading, report style.</p><hr><h2 id="_5-test-generation-ai-assisted" tabindex="-1">5. Test Generation (AI-Assisted) <a class="header-anchor" href="#_5-test-generation-ai-assisted" aria-label="Permalink to &quot;5. Test Generation (AI-Assisted)&quot;">​</a></h2><p><strong>Section title:</strong> Test Generation (AI-Assisted)</p><p><strong>Core concept:</strong> Suggestions for tests are drafted; a human edits and signs off. Coverage grows by curated addition, not automatic generation.</p><p><strong>Visual metaphor:</strong> A net or grid being mended: new strands are added by hand to fill gaps, with a pair of hands (or a single hand) tying or weaving a strand into place.</p><p><strong>Composition description:</strong> A portion of a net or grid—suggested by crossing pencil lines—with a gap and one or two new strands being woven in. Focus on the act of adding and securing, not on the whole net.</p><p><strong>Foreground elements:</strong> The net/grid, the new strand, hands or a tool (e.g. needle) completing the weave.</p><p><strong>Background elements:</strong> Faint continuation of the net or empty space; no literal “code” or screens.</p><p><strong>Labels:</strong> None.</p><p><strong>Suggested image prompt:</strong> Pencil sketch. A hand mending a net or grid—adding a strand to fill a gap. Hand-sketched lines, light pencil shading, white paper. Metaphor for filling coverage gaps with human-curated additions. Calm, technical report style.</p><hr><h2 id="_6-documentation-ai-assisted" tabindex="-1">6. Documentation (AI-Assisted) <a class="header-anchor" href="#_6-documentation-ai-assisted" aria-label="Permalink to &quot;6. Documentation (AI-Assisted)&quot;">​</a></h2><p><strong>Section title:</strong> Documentation (AI-Assisted)</p><p><strong>Core concept:</strong> Drafts are generated from context; a human revises and approves. Docs stay in sync through deliberate updates, not autonomous pushes.</p><p><strong>Visual metaphor:</strong> A book or ledger open to a page being updated: one hand holds a pencil and edits a line; the other hand (or the edge of the page) suggests the “source” (code/config) as a smaller note or reference.</p><p><strong>Composition description:</strong> Open book or ledger in soft perspective. One page has a few ruled lines; a hand with a pencil edits one line. A small slip of paper or margin suggests reference material. Quiet, studious.</p><p><strong>Foreground elements:</strong> The open book, the edited line, the pencil, optional reference slip.</p><p><strong>Background elements:</strong> Desk or surface; minimal.</p><p><strong>Labels:</strong> None, or a single minimal mark to suggest “updated”.</p><p><strong>Suggested image prompt:</strong> Pencil drawing. Open book or ledger with a hand editing a line in pencil; a small reference note nearby. Human revising a draft. Hand-sketched, light shading, white or textured paper, professional tone.</p><hr><h2 id="_7-tooling-comparison-oss-vs-saas" tabindex="-1">7. Tooling Comparison (OSS vs SaaS) <a class="header-anchor" href="#_7-tooling-comparison-oss-vs-saas" aria-label="Permalink to &quot;7. Tooling Comparison (OSS vs SaaS)&quot;">​</a></h2><p><strong>Section title:</strong> Tooling Comparison (OSS vs SaaS)</p><p><strong>Core concept:</strong> Two categories of tools—one self-contained and local (OSS / no AI cost), one external and capped (SaaS)—feeding the same pipeline under a budget.</p><p><strong>Visual metaphor:</strong> Two streams or conduits (one labelled by context as “own water”, one as “metered supply”) feeding into a single basin or reservoir with a simple gauge or marker for “limit”.</p><p><strong>Composition description:</strong> Two parallel conduits or channels—suggested by pencil lines—converging into one vessel. A simple level line or gauge on the vessel indicates a cap. No logos or product imagery.</p><p><strong>Foreground elements:</strong> The two conduits, the single vessel, the gauge/limit line.</p><p><strong>Background elements:</strong> Neutral ground; no extra detail.</p><p><strong>Labels:</strong> Optional: very small “OSS” and “capped” (or similar) in pencil, only if needed.</p><p><strong>Suggested image prompt:</strong> Pencil sketch. Two hand-drawn channels or pipes feeding into one container with a clear “max” level marked. Metaphor for OSS + capped SaaS feeding one pipeline. Light pencil, white paper, diagrammatic, report style.</p><hr><h2 id="_8-governance-and-controls" tabindex="-1">8. Governance and Controls <a class="header-anchor" href="#_8-governance-and-controls" aria-label="Permalink to &quot;8. Governance and Controls&quot;">​</a></h2><p><strong>Section title:</strong> Governance and Controls</p><p><strong>Core concept:</strong> Clear boundaries around what data can leave; controls (policy, redaction, approval, deployment checklist) guard the perimeter.</p><p><strong>Visual metaphor:</strong> A garden or courtyard with a low wall and a single gate. Inside: “safe” area (suggested by order or clarity). Outside: no detail, just implied “beyond”. A figure stands at the gate with a checklist or key.</p><p><strong>Composition description:</strong> Low wall and gate in pencil; interior suggested by a few ordered elements (e.g. paths, one tree). The gate is the only opening. One figure at the gate, back or side view, holding a small list or key.</p><p><strong>Foreground elements:</strong> Wall, gate, figure at gate, optional checklist.</p><p><strong>Background elements:</strong> Interior order; exterior left vague.</p><p><strong>Labels:</strong> None, or one subtle “boundary” if needed.</p><p><strong>Suggested image prompt:</strong> Pencil drawing. A walled garden or courtyard with one gate; a figure at the gate with a checklist. Metaphor for data boundaries and controlled access. Hand-sketched, light shading, white paper, no cartoon style.</p><hr><h2 id="_9-90-day-roadmap" tabindex="-1">9. 90-Day Roadmap <a class="header-anchor" href="#_9-90-day-roadmap" aria-label="Permalink to &quot;9. 90-Day Roadmap&quot;">​</a></h2><p><strong>Section title:</strong> 90-Day Roadmap</p><p><strong>Core concept:</strong> A fixed horizon in three phases: foundation, then optional trials, then review and decision. Time is explicit and bounded.</p><p><strong>Visual metaphor:</strong> A path or timeline as a single ribbon or strip divided into three segments, with simple landmarks in each (e.g. a post, a gate, a flag). One figure walks the path or stands at the first milestone.</p><p><strong>Composition description:</strong> Horizontal ribbon or path in pencil, clearly divided into three parts. Minimal landmarks—post, gate, flag—in each part. Small figure at the start or at the first divide. No calendar UI.</p><p><strong>Foreground elements:</strong> The three segments, the landmarks, the figure.</p><p><strong>Background elements:</strong> Slight suggestion of landscape or horizon; minimal.</p><p><strong>Labels:</strong> Optional: “0–30”, “30–60”, “60–90” in very small pencil only if needed.</p><p><strong>Suggested image prompt:</strong> Pencil sketch. A path or ribbon in three segments with simple milestones; a single figure at the first segment. 90-day pilot as a journey. Hand-drawn, light shading, white paper, report style.</p><hr><h2 id="_10-kpis-and-risks" tabindex="-1">10. KPIs and Risks <a class="header-anchor" href="#_10-kpis-and-risks" aria-label="Permalink to &quot;10. KPIs and Risks&quot;">​</a></h2><p><strong>Section title:</strong> KPIs and Risks</p><p><strong>Core concept:</strong> A few measurable outcomes and a set of hard stop conditions: what is measured, and what triggers pause or review.</p><p><strong>Visual metaphor:</strong> A balance or pair of scales: on one side, a small stack of “measures” (e.g. ruled cards or tokens); on the other, a small stack of “triggers” (similar but distinct). A hand holds a pencil or pointer, suggesting review.</p><p><strong>Composition description:</strong> Simple balance—two pans or trays—with abstract “items” on each side (e.g. small rectangles or tokens). One hand with pencil or pointer near the balance, suggesting reading or deciding. No literal numbers or dials.</p><p><strong>Foreground elements:</strong> The balance, the two sets of tokens/cards, the hand with pencil.</p><p><strong>Background elements:</strong> Desk or surface; otherwise empty.</p><p><strong>Labels:</strong> Optional: “measure” and “trigger” in tiny pencil; no numerals.</p><p><strong>Suggested image prompt:</strong> Pencil drawing. A hand-drawn balance with small tokens or cards on each side; a hand with a pencil reviews the balance. Metaphor for KPIs and stop conditions. Light pencil, white paper, minimal shading, technical report style.</p><hr><h2 id="style-reminder-all-sections" tabindex="-1">Style reminder (all sections) <a class="header-anchor" href="#style-reminder-all-sections" aria-label="Permalink to &quot;Style reminder (all sections)&quot;">​</a></h2><ul><li><strong>Medium:</strong> Pencil on white or lightly textured paper.</li><li><strong>Line:</strong> Hand-sketched, not vector-perfect.</li><li><strong>Colour:</strong> Pencil plus light colour wash only — soft grey lines, very light cream or sepia tint, minimal pale blue or warm grey accents; no saturated or digital colour.</li><li><strong>Tone:</strong> Calm, professional, suitable for engineering/technical reports.</li><li><strong>Avoid:</strong> Literal screens, UIs, robots, cartoon faces, exaggerated tech (gears, glowing chips), marketing flair.</li><li><strong>Emphasise:</strong> Symbolic metaphors, human-in-control, gates and boundaries, ordered steps, and clarity of concept over literal representation.</li></ul>',105)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
